mapper.select:
SELECT

FROM xiaoxi_tongzhi


        AND biaoti LIKE CONCAT('%',#{params.biaoti},'%')


        AND leixing = #{params.leixing}


        AND jieshouren_xuehao = #{params.jieshourenXuehao}


        AND jieshouren_gonghao = #{params.jieshourenGonghao}


        AND jieshouren_juese = #{params.jieshourenJuese}


        AND is_read = #{params.isRead}


ORDER BY addtime DESC
